package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testIsLineBreak() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);

        // Test for line break character
        boolean resultLineBreak = (boolean) isLineBreakMethod.invoke(null, '\n');
        assertTrue(resultLineBreak);

        // Test for non-line break character
        boolean resultNonLineBreak = (boolean) isLineBreakMethod.invoke(null, 'a');
        assertFalse(resultNonLineBreak);
    }

